import{_ as t,o as a,c as r,a1 as n}from"./chunks/framework.BX4nIuL2.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/12material&tool/material.md","filePath":"courses/fab-course/doc/12material&tool/material.md"}'),s={name:"courses/fab-course/doc/12material&tool/material.md"};function o(i,e,l,c,h,m){return a(),r("div",null,[...e[0]||(e[0]=[n('<h3 id="_1-periodic-table-of-the-elements" tabindex="-1"><a href="https://ptable.com/?lang=zh-hans#%E6%80%A7%E8%B4%A8" target="_blank" rel="noreferrer">1.Periodic Table of the Elements</a> <a class="header-anchor" href="#_1-periodic-table-of-the-elements" aria-label="Permalink to &quot;[1.Periodic Table of the Elements](https://ptable.com/?lang=zh-hans#%E6%80%A7%E8%B4%A8)&quot;">​</a></h3><p><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/perodictableelements.jpeg" alt=""></p><h3 id="_2-cmf" tabindex="-1"><a href="https://profabx.com/#/en/prototype/prototype" target="_blank" rel="noreferrer">2.CMF</a> <a class="header-anchor" href="#_2-cmf" aria-label="Permalink to &quot;[2.CMF](https://profabx.com/#/en/prototype/prototype)&quot;">​</a></h3><p><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/cmf.png" alt=""></p><h4 id="_2-1-color" tabindex="-1">2.1 Color <a class="header-anchor" href="#_2-1-color" aria-label="Permalink to &quot;2.1 Color&quot;">​</a></h4><p>There are a few color systems that have been developed over the years to ensure that nothing is lost in translation between designer and manufacturer.</p><p>The most common tools for achieving agreement on color standards are the <a href="https://www.pantone.com/color-systems/pantone-color-systems-explained" target="_blank" rel="noreferrer">Pantone Matching System</a>, and RAL Color System . US-based designers and engineers tend to use the Pantone Matching System, while RAL remains popular in parts of Europe. Manufacturers that work with global customers will typically be familiar with both systems.</p><p><a href="https://www.pantone.com/color-systems/pantone-color-systems-explained" target="_blank" rel="noreferrer">Pantone Matching System</a><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/cmyk.png" alt=""></p><p>[RAL Color System](RAL Color System) <img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/ral_cassic-CMYK.jpg" alt=""></p><p><a href="https://www.color-meanings.com/cmyk-color-model/" target="_blank" rel="noreferrer">CMYK</a><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/rgbcmyk.png" alt=""> Process colors utilize a limited number of inks, such as cyan, magenta, yellow and black (CMYK), applied in different ratios to create a variety of colors. Process colors are generally used when color accuracy or range is less critical.</p><h4 id="_2-2material" tabindex="-1"><a href="https://www.pacific-research.com/what-types-of-materials-are-used-in-manufacturing-prl/" target="_blank" rel="noreferrer">2.2Material</a> <a class="header-anchor" href="#_2-2material" aria-label="Permalink to &quot;[2.2Material](https://www.pacific-research.com/what-types-of-materials-are-used-in-manufacturing-prl/)&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Material</th><th style="text-align:center;">Common Uses</th><th style="text-align:center;">Subcategories</th><th style="text-align:center;">Advantage</th><th style="text-align:right;">Disadvantage</th></tr></thead><tbody><tr><td>Metals</td><td style="text-align:center;">This material is typically shiny and lustrous. It is malleable and an excellent electrical conductor</td><td style="text-align:center;">Aluminum<br>Copper<br>Tin<br>Steel<br>Bronze<br>etc</td><td style="text-align:center;">Durable<br>High-quality results<br>Heat and cold resistant</td><td style="text-align:right;">Can be challenging to<br>work with<br>Higher cost<br>Difficult to source</td></tr><tr><td>Polymers</td><td style="text-align:center;">At the molecular level, polymers are comprised of a large number of similar units and can be either synthetic or natural.</td><td style="text-align:center;">Polyethylene<br>Nylon<br>Teflon<br>Cellulose<br>Rubber</td><td style="text-align:center;">Easy to source<br>Inexpensive<br>Simple to work with</td><td style="text-align:right;">Lower-quality results<br>Less durability<br>Limited heat capacity</td></tr><tr><td>Ceramics</td><td style="text-align:center;">These are nonmetallic materials―typically clay, but not always―formed using high heat.</td><td style="text-align:center;">Glass<br>Cement<br>Clay<br>Porcelain<br>Stoneware</td><td style="text-align:center;">Lightweight<br>Robust electrical<br>insulation<br>Inexpensive</td><td style="text-align:right;">Dimensional tolerances can be inconsistent<br>Cracking is possible<br>Processing can be challenging</td></tr><tr><td>Composites</td><td style="text-align:center;">This involves combining two or more disparate materials to create a new, unique material.</td><td style="text-align:center;">Concrete<br>Plywood<br>Fiberglass<br>Paper<br>Reinforced plastics</td><td style="text-align:center;">High durability<br>Customizability<br>Affordability</td><td style="text-align:right;">Can be bad for the environment<br>Repair is challenging<br>May require special handling</td></tr></tbody></table><h5 id="metal" tabindex="-1">Metal <a class="header-anchor" href="#metal" aria-label="Permalink to &quot;Metal&quot;">​</a></h5><p><a href="https://www.iqsdirectory.com/articles/aluminum-metal/types-of-aluminum.html#/" target="_blank" rel="noreferrer">Aluminum</a><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/iqsdirectory.png" alt=""></p><table tabindex="0"><thead><tr><th>Serial</th><th style="text-align:center;">Main alloying elements</th><th style="text-align:center;">Principal</th><th style="text-align:center;">Example application</th></tr></thead><tbody><tr><td>1xxx</td><td style="text-align:center;">99.xx% pure aluminum</td><td style="text-align:center;">High electrical and thermal conductivity, excellent corrosion resistance.</td><td style="text-align:center;">Electrical conductors and chemical processing equipment.</td></tr><tr><td>2xxx</td><td style="text-align:center;">Copper</td><td style="text-align:center;">High strength-to-weight ratio, low corrosion resistance</td><td style="text-align:center;">Truck wheels and suspensions, aircraft fuselage, and wings</td></tr><tr><td>3xxx</td><td style="text-align:center;">Manganese</td><td style="text-align:center;">Moderate strength and good workability.</td><td style="text-align:center;">General sheet work, recreation vehicles, electronics.</td></tr><tr><td>4xxx</td><td style="text-align:center;">Silicon</td><td style="text-align:center;">Low melting point and thermal expansion, high wear resistance.</td><td style="text-align:center;">Welding wire and brazing alloy, architectural applications, forged engine pistons.</td></tr><tr><td>5xxx</td><td style="text-align:center;">Magnesium</td><td style="text-align:center;">Moderate-to-high strength, good weldability, good corrosion resistance.</td><td style="text-align:center;">Appliances, automotive parts, marine components.</td></tr><tr><td>6xxx</td><td style="text-align:center;">Silicon and magnesium</td><td style="text-align:center;">Medium strength with good formability, weldability, machinability, and corrosion resistance.</td><td style="text-align:center;">Structural applications, architectural extrusions, recreational equipment.</td></tr><tr><td>7xxx</td><td style="text-align:center;">Zinc</td><td style="text-align:center;">Moderate-to-very high strength.</td><td style="text-align:center;">Airframe structures, mobile equipment, high-stress parts.</td></tr><tr><td>8xx.x</td><td style="text-align:center;">Tin</td><td style="text-align:center;">Low friction.</td><td style="text-align:center;">Bearing and bushing applications.</td></tr></tbody></table><p><a href="https://www.britannica.com/technology/steel/Wear-resistant-steels" target="_blank" rel="noreferrer">Steel</a></p><table tabindex="0"><thead><tr><th>Element</th><th style="text-align:center;">Effect</th></tr></thead><tbody><tr><td>Nickel</td><td style="text-align:center;">2-5% nickel content increases toughness12-20% nickel content increases corrosion resistance</td></tr><tr><td>Manganese</td><td style="text-align:center;">0.25%-0.4% manganese content with a bit of sulphur can lessen brittlenessOver 1% will increase hardenability</td></tr><tr><td>Silicon</td><td style="text-align:center;">0.2-0.7% silicon content increases hardenability and strength2% silicon content</td></tr><tr><td>Chromium</td><td style="text-align:center;">0.5-2% chromium content increases hardenability4-18% chromium content increases corrosion resistance</td></tr><tr><td>Boron</td><td style="text-align:center;">0.001-0.003% boron content increases hardenability</td></tr><tr><td>Copper</td><td style="text-align:center;">0.1-0.4% copper content increases corrosion resistan</td></tr><tr><td><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/flowline1_540.gif" alt=""></td><td style="text-align:center;"></td></tr><tr><td><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/Steel-tubing.png" alt=""></td><td style="text-align:center;"></td></tr></tbody></table><p><a href="https://waykenrm.com/blogs/differences-between-brass-bronze-and-copper/#/" target="_blank" rel="noreferrer">Copper</a><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/applications-of-brass-bronze-and-copper-optimized.jpg" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240602-230239.png" alt=""><a href="./.html">Titanium</a><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240602-231154.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240602-231627.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240602-231627.png" alt=""></p><h5 id="polymers" tabindex="-1"><a href="https://www.findlight.net/blog/plastic-manufacturing-processes-brief-guide/#/" target="_blank" rel="noreferrer">Polymers</a> <a class="header-anchor" href="#polymers" aria-label="Permalink to &quot;[Polymers](https://www.findlight.net/blog/plastic-manufacturing-processes-brief-guide/#/)&quot;">​</a></h5><p><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/PlasticsPyramid3.jpg" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/Blog1.2.png" alt=""></p><h5 id="ceramics" tabindex="-1">Ceramics <a class="header-anchor" href="#ceramics" aria-label="Permalink to &quot;Ceramics&quot;">​</a></h5><p><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240602-234029.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240602-233806.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/ceramicsvehicle.png" alt=""></p><h5 id="composites" tabindex="-1"><a href="https://www.addcomposites.com/post/where-are-composites-used#/" target="_blank" rel="noreferrer">Composites</a> <a class="header-anchor" href="#composites" aria-label="Permalink to &quot;[Composites](https://www.addcomposites.com/post/where-are-composites-used#/)&quot;">​</a></h5><p><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/1482836070.materiau.composite.eng.web.jpg" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/fiber-resin-combo.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/FiberMatrixComposite3.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240602-234440.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240602-234553.png" alt=""></p><p><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/liquidmetal.png" alt=""></p><h4 id="finish" tabindex="-1">Finish <a class="header-anchor" href="#finish" aria-label="Permalink to &quot;Finish&quot;">​</a></h4><p><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/Post-processing-methods-Post-Processing.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/bottle3.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240602-235325.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240602-235312.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/surface-finish.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/1619405031756t.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240603-000623%402x.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240603-000609%402x.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240603-001452.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240603-001907.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240603-001939.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20240603-002159.png" alt=""></p><h3 id="_3-performance" tabindex="-1"><a href="./.html">3.Performance</a> <a class="header-anchor" href="#_3-performance" aria-label="Permalink to &quot;[3.Performance]()&quot;">​</a></h3><p><a href="https://glossar.item24.com/en/glossary-index/article/item//shore-hardness-test.html" target="_blank" rel="noreferrer">Shore hardness test</a><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/phpBDSm94.png" alt=""><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/shore-hardness-scale.jpg" alt=""></p><p><a href="https://www.chegg.com/homework-help/questions-and-answers/compare-influence-different-indenter-shapes-rockwell-hardness-test-please-comment-items-gi-q95179475" target="_blank" rel="noreferrer">Other method</a><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/WX20231219-091144.png" alt=""><a href="https://slideplayer.com/slide/17420242/" target="_blank" rel="noreferrer">Strengh young module</a><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/youngmodule.png" alt=""><a href="https://slideplayer.com/slide/17420242/" target="_blank" rel="noreferrer">Young-Density module</a><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/densityyoung.png" alt=""><a href="https://slideplayer.com/slide/17420242/" target="_blank" rel="noreferrer">Strength-Density module</a><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/strengthdensity.png" alt=""><a href="https://slideplayer.com/slide/17420242/" target="_blank" rel="noreferrer">Max service temparture</a><img src="https://nexmaker-profabx.oss-cn-hangzhou.aliyuncs.com/img/TEMPERATURE.png" alt=""></p><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><ul><li><a href="https://www.arptech.com.au/blog/shore-hardness-scale.htm" target="_blank" rel="noreferrer">Arptech</a></li><li><a href="https://www.chegg.com/homework-help/questions-and-answers/compare-influence-different-indenter-shapes-rockwell-hardness-test-please-comment-items-gi-q95179475" target="_blank" rel="noreferrer">Chegg</a></li><li><a href="https://slideplayer.com/slide/17420242/" target="_blank" rel="noreferrer">slideplayer</a></li><li><a href="https://www.matweb.com/search/MaterialGroupSearch.aspx" target="_blank" rel="noreferrer">matweb</a></li><li><a href="https://www.youtube.com/watch?v=NC63Xx2N1-8&amp;ab_channel=RotherTechnologie" target="_blank" rel="noreferrer">Video:CNC</a></li><li><a href="https://www.youtube.com/watch?v=LP7f_fvVJH4&amp;ab_channel=UnboxTherapy" target="_blank" rel="noreferrer">Video:World Exclusive Product Launch From CMF by Nothing</a></li><li><a href="https://www.youtube.com/watch?v=N61PU2ZkYtA&amp;ab_channel=EricStrebel" target="_blank" rel="noreferrer">Video:How to get a High gloss finish on a model or prototype</a></li><li><a href="https://www.youtube.com/watch?v=7IA9LWU4iHo&amp;ab_channel=cwvideomaker" target="_blank" rel="noreferrer">Apple iPhone manufacturing video</a></li><li><a href="https://www.youtube.com/watch?v=GQnr-kfuVdQ&amp;ab_channel=EEStore" target="_blank" rel="noreferrer">Video:Making the all new Mac Pro</a></li><li><a href="https://www.youtube.com/watch?v=qmaYUhMH1w8&amp;ab_channel=RandomVids" target="_blank" rel="noreferrer">Video：How the Apple Watch is made</a></li><li><a href="https://www.youtube.com/watch?v=xGYZqmGjG9s&amp;ab_channel=Ekeeda" target="_blank" rel="noreferrer">Video: composite</a></li></ul>',32)])])}const d=t(s,[["render",o]]);export{p as __pageData,d as default};
